// capnwasm/codegen: single-file bundle that ships the upstream Cap'n Proto
// schema COMPILER (cpp/vendor/capnp/compiler) statically linked through
// zig cc, base64-embedded, with its JS loader. Use this when you want to
// run schema codegen at runtime. Including in a browser, where there is
// no filesystem and no external 'capnp' binary. Standard schemas
// (c++.capnp, schema.capnp, etc.) are baked into the wasm so user
// imports of "/capnp/c++.capnp" resolve with zero host I/O.
//
// Generated by js/build_codegen_inlined.mjs. Do not edit by hand.

// Minimal wasi_snapshot_preview1 polyfill for the capnp runtime wasm.
// The runtime declares only 5 wasi imports. Args, fd_write, proc_exit,
// fd_close. Keeping this separate from the full schema-compiler shim
// lets RPC-only browser bundles ship just the bytes they need.

export function makeMemRefs() {
  let mem;
  return {
    setMemory(m) { mem = m; },
    readBytes(ptr, len) { return new Uint8Array(mem.buffer, ptr, len); },
    writeUint32(ptr, value) { new DataView(mem.buffer).setUint32(ptr, value, true); },
    dvFor() { return new DataView(mem.buffer); },
  };
}

export function runtimeImports({ readBytes, writeUint32, dvFor }) {
  return {
    args_get(_argv_ptr, _argv_buf_ptr) { return 0; },
    args_sizes_get(argc_ptr, argv_buf_size_ptr) {
      writeUint32(argc_ptr, 0);
      writeUint32(argv_buf_size_ptr, 0);
      return 0;
    },
    // fd_write forwards stdout (fd=1) and stderr (fd=2) to console.
    // Other fds get the byte count back so the caller treats it as a
    // successful no-op write.
    fd_write(fd, iovs_ptr, iovs_len, nwritten_ptr) {
      let total = 0;
      const dv = dvFor();
      for (let i = 0; i < iovs_len; i++) {
        const ptr = dv.getUint32(iovs_ptr + i * 8, true);
        const len = dv.getUint32(iovs_ptr + i * 8 + 4, true);
        if (fd === 1 || fd === 2) {
          const text = new TextDecoder().decode(readBytes(ptr, len));
          (fd === 2 ? console.error : console.log)(text.replace(/\n$/, ""));
        }
        total += len;
      }
      writeUint32(nwritten_ptr, total);
      return 0;
    },
    proc_exit(code) { throw new Error(`capnp_cpp: proc_exit(${code})`); },
    fd_close(_fd) { return 0; },
  };
}

/** Just the 5 imports the runtime wasm declares. */
export function buildRuntimeWasiImports() {
  const refs = makeMemRefs();
  return { setMemory: refs.setMemory, imports: runtimeImports(refs) };
}


// Browser-side polyfill for the wasi_snapshot_preview1 imports the C++
// schema compiler wasm pulls in. Browsers don't expose WASI natively;
// this supplies just enough to satisfy the linker and forward stderr
// writes.
//
// The runtime wasm only declares 5 imports (args, fd_write, proc_exit,
// fd_close). Those live in cpp_wasi_runtime.mjs so the runtime loader
// stays small and bundlers don't drag the full shim into RPC-only
// browser bundles.



export function buildWasiImports() {
  const refs = makeMemRefs();
  const { setMemory, readBytes, writeUint32 } = refs;
  return {
    setMemory,
    imports: {
      ...runtimeImports(refs),

      // ---- Compiler-only imports (capnpc.opt.wasm) -------------------
      environ_get(_env_ptr, _env_buf_ptr) { return 0; },
      environ_sizes_get(envc_ptr, envbuf_size_ptr) {
        writeUint32(envc_ptr, 0);
        writeUint32(envbuf_size_ptr, 0);
        return 0;
      },
      clock_time_get(_id, _precision, time_ptr) {
        const ns = BigInt(Date.now()) * 1_000_000n;
        refs.dvFor().setBigUint64(time_ptr, ns, true);
        return 0;
      },
      random_get(buf_ptr, buf_len) {
        const out = readBytes(buf_ptr, buf_len);
        if (typeof crypto !== "undefined" && crypto.getRandomValues) {
          for (let off = 0; off < buf_len; off += 65536) {
            crypto.getRandomValues(out.subarray(off, Math.min(off + 65536, buf_len)));
          }
        } else {
          for (let i = 0; i < buf_len; i++) out[i] = (Math.random() * 256) & 0xff;
        }
        return 0;
      },
      // Filesystem: the compiler uses a virtual in-memory filesystem
      // provided by our wrapper; these wasi imports get called only on
      // init paths libc walks (e.g. probing whether stdout is a terminal).
      // Return ENOSYS / EBADF as appropriate.
      fd_seek(_fd, _offset, _whence, _newoffset_ptr) { return 8; },
      fd_read(_fd, _iovs_ptr, _iovs_len, _nread_ptr) { return 8; },
      fd_fdstat_get(_fd, _stat_ptr) { return 8; },
      fd_fdstat_set_flags(_fd, _flags) { return 8; },
      fd_prestat_get(_fd, _prestat_ptr) { return 8; },
      fd_prestat_dir_name(_fd, _path_ptr, _path_len) { return 8; },
      path_open() { return 8; },
      path_filestat_get() { return 8; },
      path_create_directory() { return 8; },
      path_remove_directory() { return 8; },
      path_unlink_file() { return 8; },
      path_rename() { return 8; },
      path_readlink() { return 8; },
      path_symlink() { return 8; },
      path_link() { return 8; },
      poll_oneoff() { return 8; },
      sched_yield() { return 0; },
    },
  };
}


const __CAPNPC_WASM_GZ_B64 = "";

function __base64ToBytes(b64) {
  if (typeof Buffer !== "undefined") return new Uint8Array(Buffer.from(b64, "base64"));
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

async function __gunzip(bytes) {
  // DecompressionStream("gzip") is universal: Node 18+, Workers, all
  // modern browsers (Chrome 80+, FF 113+, Safari 16.4+).
  const ds = new DecompressionStream("gzip");
  const stream = new Response(bytes).body.pipeThrough(ds);
  return new Uint8Array(await new Response(stream).arrayBuffer());
}

const EMBEDDED_STANDARD_COUNT = 6;  // matches cpp/embed_standard_schemas.sh

export class CapnpCompiler {
  #instance;
  #memory;
  #exports;
  #u8() { return new Uint8Array(this.#memory.buffer); }
  #extraFiles = [];
  #addedThisCompile = 0;

  static async load() {
    const bytes = await __gunzip(__base64ToBytes(__CAPNPC_WASM_GZ_B64));
    const wasi = buildWasiImports();
    const { instance } = await WebAssembly.instantiate(bytes, {
      wasi_snapshot_preview1: wasi.imports,
    });
    wasi.setMemory(instance.exports.memory);
    const c = new CapnpCompiler();
    c.#instance = instance;
    c.#memory = instance.exports.memory;
    c.#exports = instance.exports;
    return c;
  }

  /** Register an extra schema resolvable by name during compile(). */
  addSchema(name, source) {
    const bytes = typeof source === "string" ? new TextEncoder().encode(source) : source;
    this.#extraFiles.push({ name, bytes });
  }

  #addFile(name, bytes) {
    const u8 = this.#u8();
    const inPtr = this.#exports.capnpc_in_ptr();
    const cap = this.#exports.capnpc_in_capacity();
    if (bytes.length > cap) throw new Error(`schema source exceeds compiler scratch (${cap} bytes)`);
    u8.set(bytes, inPtr);
    const nameBytes = new TextEncoder().encode(name);
    if (bytes.length + nameBytes.length > cap) throw new Error("name + source exceeds scratch");
    u8.set(nameBytes, inPtr + bytes.length);
    if (this.#exports.capnpc_add_file(inPtr + bytes.length, nameBytes.length, bytes.length) !== 1) {
      throw new Error(`capnpc_add_file(${name}) failed`);
    }
    this.#addedThisCompile++;
  }

  /**
   * Compile a single .capnp source. Returns the binary CodeGeneratorRequest
   * (Cap'n Proto framed message) as a Uint8Array, or throws with the
   * concatenated error text. Standard schemas are pre-loaded inside the
   * wasm itself; addSchema() lets you register more.
   */
  async compile(name, source) {
    const sourceBytes = typeof source === "string" ? new TextEncoder().encode(source) : source;
    this.#addedThisCompile = 0;
    this.#exports.capnpc_reset();
    for (const extra of this.#extraFiles) this.#addFile(extra.name, extra.bytes);
    this.#addFile(name, sourceBytes);
    const userIdx = EMBEDDED_STANDARD_COUNT + this.#extraFiles.length + this.#addedThisCompile - 1;
    const len = this.#exports.capnpc_compile(userIdx);
    if (len === 0) {
      const errLen = this.#exports.capnpc_get_errors();
      const u8 = this.#u8();
      const outPtr = this.#exports.capnpc_out_ptr();
      const errText = new TextDecoder().decode(u8.slice(outPtr, outPtr + errLen));
      throw new Error(`capnp compile failed:\n${errText || "(no error text)"}`);
    }
    const u8 = this.#u8();
    const outPtr = this.#exports.capnpc_out_ptr();
    return u8.slice(outPtr, outPtr + len);
  }

  /** One-shot compile + extract a struct model in our codegen-ready shape. */
  async compileToModel(name, source) {
    const requestBytes = await this.compile(name, source);
    const u8 = this.#u8();
    const inPtr = this.#exports.capnpc_in_ptr();
    new DataView(u8.buffer).setUint32(inPtr, requestBytes.length, true);
    u8.set(requestBytes, inPtr + 4);
    const len = this.#exports.capnpc_extract_structs();
    if (len === 0) throw new Error("capnpc_extract_structs failed");
    const outPtr = this.#exports.capnpc_out_ptr();
    const json = new TextDecoder().decode(u8.slice(outPtr, outPtr + len));
    const raw = JSON.parse(json);
    // Include interface nodes in byId so Capability(<Iface>) field types
    // resolve to a real interface name (matching capnpc_loader.mjs).
    const ifaces = this.extractInterfaces();
    const refs = [...raw, ...ifaces];
    return raw.map(s => translateStruct(s, refs));
  }

  /**
   * Extract interface metadata from the most recently compiled request.
   * Must be called after compileToModel; they share the buffered
   * CodeGeneratorRequest in capnpc_in. Returns
   *   [{ name, id, methods: [{ id, name, paramStructId, resultStructId }] }, ...]
   * or an empty array when the schema declares no interfaces.
   */
  extractInterfaces() {
    const len = this.#exports.capnpc_extract_interfaces();
    if (len === 0) return [];
    const outPtr = this.#exports.capnpc_out_ptr();
    const u8 = this.#u8();
    const json = new TextDecoder().decode(u8.slice(outPtr, outPtr + len));
    return JSON.parse(json);
  }
}

// Map from Cap'n Proto schema type to the canonical type name our codegen
// uses. Primitives map directly; struct/enum refs resolve their name from
// the request's id table. Lists return a structured marker so the
// generator can emit element-type-aware accessors. Brand bindings on
// struct/interface refs produce specialized names (e.g. `Box$Tag` for
// `Box(Tag)`) — see synthesizeSpecializations below for how those names
// get backed by a real synthesized struct entry.
//
// `paramScope` is the scopeId of the surrounding generic struct (or
// undefined). When resolving an AnyPointer.parameter type, we look up
// the binding in `brandStack` for matching scopeIds.
function typeToName(t, byId, brandStack) {
  if (typeof t === "string") return t;  // primitive
  if (t.list) {
    const inner = typeToName(t.list, byId, brandStack);
    return `List(${inner})`;
  }
  if (t.struct) {
    const base = byId.get(String(t.struct))?.name ?? "AnyPointer";
    if (t.brand && t.brand.scopes && t.brand.scopes.length > 0) {
      const suffix = brandSuffix(t.brand, byId, brandStack);
      if (suffix) return `${base}${suffix}`;
    }
    return base;
  }
  if (t.enum)      return byId.get(String(t.enum))?.name ?? "UInt16";
  // Interface-typed (capability) fields: tagged so codegen can emit a
  // null-returning getter / null-accepting setter without colliding with
  // a same-named struct. Resolving the cap proper requires an RPC cap
  // table, which non-RPC openers (openDynamic, raw bytes) don't have.
  if (t.interface) {
    const ifaceName = byId.get(String(t.interface))?.name ?? "AnyPointer";
    return `Capability(${ifaceName})`;
  }
  if (t.parameter) {
    // Generic parameter reference. Resolve via the surrounding brand
    // stack: walk outward until we find a scope matching this scopeId,
    // then pick the binding at the parameter's index.
    if (brandStack) {
      for (let i = brandStack.length - 1; i >= 0; i--) {
        const brand = brandStack[i];
        const scope = (brand?.scopes ?? []).find(s => String(s.scopeId) === String(t.parameter.scopeId));
        if (scope && Array.isArray(scope.bind)) {
          const binding = scope.bind[t.parameter.index];
          if (binding && binding.type !== undefined) {
            return typeToName(binding.type, byId, brandStack.slice(0, i));
          }
        }
      }
    }
    return "AnyPointer";
  }
  return "AnyPointer";
}

// Build a name suffix from a brand. For Box(Tag) -> "$Tag". For
// Box(List(Text)) -> "$List_Text". The exact form is deterministic so
// the same (struct, brand) tuple always produces the same name.
function brandSuffix(brand, byId, brandStack) {
  const parts = [];
  for (const scope of (brand.scopes ?? [])) {
    if (!Array.isArray(scope.bind)) continue;
    for (const binding of scope.bind) {
      if (binding && binding.type !== undefined) {
        const inner = typeToName(binding.type, byId, brandStack);
        parts.push(sanitizeNamePart(inner));
      } else {
        parts.push("AnyPointer");
      }
    }
  }
  if (parts.length === 0) return "";
  return "$" + parts.join("_");
}

// Convert a possibly-nested capnp type name (e.g. "List(Text)") into
// something safe to use inside a JS identifier. List/Capability
// wrappers become snake-style segments.
function sanitizeNamePart(name) {
  return String(name)
    .replace(/^List\(([^)]*)\)$/, (_, inner) => "List_" + sanitizeNamePart(inner))
    .replace(/^Capability\(([^)]*)\)$/, (_, inner) => "Cap_" + sanitizeNamePart(inner))
    .replace(/[^A-Za-z0-9_]/g, "_");
}

// For the codegen we also need to know whether a struct ref resolves to a
// known struct (so we can emit a typed Reader for it) or is opaque.
function structNameOrNull(t, byId) {
  if (t && t.struct) return byId.get(String(t.struct))?.name ?? null;
  return null;
}

// Bit width for Cap'n Proto data-section primitive types. Used to convert
// slot.offset (which is in units of the type's width) to a bit offset.
const TYPE_WIDTHS = {
  Bool: 1, Int8: 8, UInt8: 8, Int16: 16, UInt16: 16,
  Int32: 32, UInt32: 32, Int64: 64, UInt64: 64,
  Float32: 32, Float64: 64,
};

// Translate a single field into 0..N codegen field entries. Groups produce
// ONE entry of kind "group" pointing at a synthetic nested struct that the
// generator emits its own Reader/Builder class for; this gives the natural
// `r.parent.child` API while still sharing the parent's wire storage.
//
// `synthAccum` is a mutable list the caller passes in to collect synthetic
// nested-struct definitions discovered during translation. The caller
// appends them to the final structs array so they get a Reader class.
//
// `brandStack` is the chain of brand bindings active at this field's
// position (innermost last). Used by typeToName to resolve generic
// parameter references when synthesizing specialized struct entries.
function translateField(f, byId, parentName, synthAccum, brandStack) {
  if (f.slot) {
    const typeName = typeToName(f.slot.type, byId, brandStack);
    const width = TYPE_WIDTHS[typeName];
    const isPtr = !width;
    return [{
      name: f.name,
      ordinal: f.ordinal,
      type: typeName,
      kind: isPtr ? "pointer" : "data",
      bitOffset: isPtr ? 0 : (f.slot.offset * width),
      bitSize: isPtr ? 0 : width,
      ptrIndex: isPtr ? f.slot.offset : undefined,
      discriminantValue: f.discriminantValue,
      // Preserve the raw type so synthesizeSpecializations can re-emit
      // the field's type under a different brand stack later.
      _rawType: f.slot.type,
    }];
  }
  if (f.group !== undefined) {
    const groupNode = byId.get(String(f.group));
    if (!groupNode) return [];
    // Synthesize a nested Reader/Builder class for the group. Its name is
    // `<Parent>_<groupField>` so it doesn't collide with any user type.
    // It shares wire storage with the parent. Its field offsets are
    // already absolute inside the containing struct (capnp's group layout
    // rule), so generated getters work unchanged.
    const synthName = `${parentName}_${f.name}`;
    const inner = translateStruct(
      { ...groupNode, name: synthName },
      // groupNode's fields are recursively translated, and any of them
      // that are themselves groups will get further synthesized.
      // Pass the accumulator so child synths land in the same array.
      [],
      byId,
      synthAccum,
      brandStack,
    );
    synthAccum.push(inner);
    return [{
      name: f.name,
      ordinal: f.ordinal,
      type: synthName,
      kind: "group",
      groupStructName: synthName,
      discriminantValue: f.discriminantValue,
    }];
  }
  return [{ name: f.name, ordinal: f.ordinal, type: "Unknown", bitOffset: 0 }];
}

function translateStruct(s, _unusedAll, byIdParam, synthAccumParam, brandStackParam) {
  // First-call public form: translateStruct(s, allStructs). Recursive form:
  // translateStruct(s, [], byId, synthAccum, brandStack). Detect by argument shape.
  const byId = byIdParam ?? new Map(_unusedAll.map(x => [String(x.id), x]));
  const synthAccum = synthAccumParam ?? [];
  const brandStack = brandStackParam ?? [];
  const fields = s.fields.flatMap(f =>
    translateField(f, byId, s.name, synthAccum, brandStack));
  const result = {
    name: s.name,
    fields,
    dataWords: s.dataWords,
    ptrWords: s.ptrWords,
    discriminantCount: s.discriminantCount,
    discriminantOffsetBits: s.discriminantOffset !== undefined ? s.discriminantOffset * 16 : undefined,
  };
  // If we're being called as the top-level translation of a user struct
  // (no synthAccumParam), append the synthesized group structs to the
  // returned model so they get codegen alongside the parent.
  if (!synthAccumParam && synthAccum.length > 0) {
    result._synthStructs = synthAccum;
  }
  return result;
}

// Walk the translated struct list looking for fields whose type names
// are specialized (`Box$Tag`, `List(Box$Tag)`, etc.) and synthesize a
// concrete struct entry for each one. The synthesized struct mirrors
// the original generic's wire layout but resolves any AnyPointer
// parameter references through the brand bindings.
//
// Idempotent: if `Box$Tag` appears in three fields, only one entry is
// synthesized. The list of types we walk grows recursively because a
// specialization's own fields can reference further specializations
// (e.g. `Box(Box(Tag))` produces both `Box$Box_Tag` and `Box$Tag`).
function synthesizeSpecializations(structs, raw, refs) {
  const byId = new Map(refs.map(x => [String(x.id), x]));
  const byName = new Map(structs.map(s => [s.name, s]));
  const rawByName = new Map(raw.filter(s => !s.isGroup).map(s => [s.name, s]));
  const synthesized = new Map(); // specName -> struct entry

  // Collect every (genericName, brand) tuple referenced from any field.
  const queue = [];
  function enqueueFromTypeName(typeName, fieldRawType) {
    if (!typeName) return;
    // Strip List(...) / Capability(...) wrappers; only struct refs synthesize.
    let m = /^List\(([^)]*)\)$/.exec(typeName);
    if (m) { enqueueFromTypeName(m[1], fieldRawType?.list); return; }
    m = /^Capability\(([^)]*)\)$/.exec(typeName);
    if (m) return; // capability brand specialization not yet emitted
    const dollarIdx = typeName.indexOf("$");
    if (dollarIdx < 0) return;
    if (synthesized.has(typeName) || byName.has(typeName)) return;
    // Resolve the raw type back to (typeId, brand). The field's _rawType
    // points at the slot's Type Reader from the JSON; for a struct ref
    // this is `{struct: id, brand: {...}}`. For wrapped types (List)
    // we recurse into the element. For mismatched cases we skip
    // synthesis — the codegen will still see the specialized name and
    // currently treats it as an unrecognized struct.
    const rawTy = unwrapToStruct(fieldRawType);
    if (!rawTy || !rawTy.struct) return;
    queue.push({ name: typeName, structId: String(rawTy.struct), brand: rawTy.brand });
  }
  for (const s of structs) {
    for (const f of s.fields) {
      enqueueFromTypeName(f.type, f._rawType);
    }
  }
  while (queue.length > 0) {
    const { name, structId, brand } = queue.shift();
    if (synthesized.has(name) || byName.has(name)) continue;
    const node = byId.get(structId);
    if (!node || !node.fields) continue;
    const brandStack = [brand];
    const synthFields = node.fields.flatMap(f =>
      translateField(f, byId, name, /* synthAccum */ [], brandStack)
    );
    const entry = {
      name,
      fields: synthFields,
      dataWords: node.dataWords,
      ptrWords: node.ptrWords,
      discriminantCount: node.discriminantCount,
      discriminantOffsetBits: node.discriminantOffset !== undefined ? node.discriminantOffset * 16 : undefined,
    };
    synthesized.set(name, entry);
    // Specialized fields may themselves reference further specializations.
    for (const f of synthFields) {
      enqueueFromTypeName(f.type, f._rawType);
    }
  }
  if (synthesized.size === 0) return structs;
  // Place specializations before their first user. Order isn't strict
  // (codegen forward-refs by name) but keeping them near the top keeps
  // dist diffs readable.
  return [...synthesized.values(), ...structs];
}

// Reach into a raw schema Type to find an inner struct ref. Walks
// List(...) wrappers; returns the struct-typed Type Reader literal or
// null if none reachable.
function unwrapToStruct(t) {
  if (!t || typeof t !== "object") return null;
  if (t.struct) return t;
  if (t.list) return unwrapToStruct(t.list);
  return null;
}

